final class BlockchainAPIClient {
    private let session: URLSession
    private let baseURL: URL

    init(baseURL: String, session: URLSession = .shared) throws {
        guard let url = URL(string: baseURL) else {
            throw WalletError.invalidURL
        }
        self.baseURL = url
        self.session = session
    }

    func broadcastTransaction(_ signedTransaction: SignedTransaction) async throws -> BlockchainTransactionResponse {
        let endpoint = baseURL.appendingPathComponent("transactions/broadcast")
        var request = URLRequest(url: endpoint)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")

        let payload = BlockchainTransactionRequest(
            payload: signedTransaction.rawTransaction,
            signature: signedTransaction.signature,
            publicKey: signedTransaction.publicKey
        )
        request.httpBody = try JSONEncoder().encode(payload)

        let (data, response) = try await session.data(for: request)

        guard let httpResponse = response as? HTTPURLResponse,
              (200..<300).contains(httpResponse.statusCode) else {
            throw WalletError.invalidResponse
        }

        return try JSONDecoder().decode(BlockchainTransactionResponse.self, from: data)
    }

    func fetchBalance(address: String) async throws -> Decimal {
        let endpoint = baseURL.appendingPathComponent("address/\(address)/balance")
        let (data, response) = try await session.data(from: endpoint)

        guard let httpResponse = response as? HTTPURLResponse,
              (200..<300).contains(httpResponse.statusCode),
              let balanceString = String(data: data, encoding: .utf8),
              let balance = Decimal(string: balanceString) else {
            throw WalletError.invalidResponse
        }

        return balance
    }
